for tt = 1:T
    for ii = 1:n_arms
        hat_r(ii) = beta_dist(ii).random();
    end
    [~, ind(tt)] = max(hat_r);

    outcome = mathcal_R(ind(tt)).random();

    beta_dist(ind(tt)).a = beta_dist(ind(tt)).a + outcome;
    beta_dist(ind(tt)).b = beta_dist(ind(tt)).b + 1 - outcome;
end
